+static bool power_law_graph(SparseMatrix A) {
+  int m, max = 0, i, *ia = A->ia, *ja = A->ja, j, deg;
+  bool res = false;
+  m = A->m;
+  int *mask = gv_calloc(m + 1, sizeof(int));
+
+  for (i = 0; i < m + 1; i++){
+    mask[i] = 0;
+  }
+
+  for (i = 0; i < m; i++){
+    deg = 0;
+    for (j = ia[i]; j < ia[i+1]; j++){
+      if (i == ja[j]) continue;
+      deg++;
+    }
+    mask[deg]++;
+    max = MAX(max, mask[deg]);
+  }
+  if (mask[1] > 0.8*max && mask[1] > 0.3*m) res = true;
+  free(mask);
+  return res;
+}
